import{_ as t,a}from"./chunks/05-powerbi-compliance-matrix.sZuSnCYX.js";import{_ as o}from"./chunks/09-auditor-md-excerpt.Uu8bSm6-.js";import{_ as s}from"./chunks/11-tui-workspace-setup.MCQvk2sM.js";import{_ as r}from"./chunks/12-tui-health-check.B9ksbbcn.js";import{_ as i}from"./chunks/13-tui-run-assessment.BB6BYCVS.js";import{_ as n}from"./chunks/14-tui-publish-html.B4-MrVrX.js";import{_ as l,o as d,c as p,a2 as c}from"./chunks/framework.DTa47_fH.js";const h="/assets/01-cli-init.DO-jCG5y.png",g="/assets/02-cli-doctor.Be4z945h.png",m="/assets/03-cli-assess-anthropic.DqsNQ_bR.png",u="/assets/06-powerbi-risks.BxxPrRBS.png",b="/assets/07-powerbi-auditor.B9K3xsFt.png",w="/assets/08-powerbi-portfolio-overview.DBtUJG9O.png",f="/assets/10-tui-main-menu.mpbnL-r0.png",k="/assets/15-mcp-connector-claude-desktop.C28IPV2O.png",v="/assets/16-mcp-deep-dive-question.BptrIUkV.png",W=JSON.parse('{"title":"SWAO Sample Gallery","description":"","frontmatter":{},"headers":[],"relativePath":"samples/index.md","filePath":"samples/index.md"}'),y={name:"samples/index.md"};function P(T,e,A,_,x,C){return d(),p("div",null,[...e[0]||(e[0]=[c('<h1 id="swao-sample-gallery" tabindex="-1">SWAO Sample Gallery <a class="header-anchor" href="#swao-sample-gallery" aria-label="Permalink to &quot;SWAO Sample Gallery&quot;">​</a></h1><p>Screenshots from real assessment runs, covering the CLI, Power BI reports, the terminal interface, and the Claude Desktop MCP connector. All captures are from SWAO v0.4.8 against live workspaces.</p><hr><h2 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h2><h3 id="sample-01" tabindex="-1"><code>swao init</code> -- workspace scaffolding <a class="header-anchor" href="#sample-01" aria-label="Permalink to &quot;`swao init` -- workspace scaffolding {#sample-01}&quot;">​</a></h3><p><img src="'+h+'" alt="swao init output alongside the created workspace folder"></p><p>A <code>swao init --name &lt;app-id&gt;</code> run with the Windows Explorer split view alongside. The command installs the GDPR community framework into <code>wsp/inputs/catalogs/community</code>, scaffolds the Power BI <code>.pbit</code> templates into <code>wsp/templates/powerbi</code>, and creates the app ingestion folder under <code>apps/&lt;app-id&gt;/ingestion</code>. The right pane shows the resulting workspace: three items ready -- <code>ingestion/</code>, <code>wsp/</code>, and <code>.swao.yml</code>.</p><p><strong>One command, portfolio-ready.</strong> No manual folder creation or template hunting.</p><hr><h3 id="sample-02" tabindex="-1"><code>swao health-check</code> -- all 11 probes <a class="header-anchor" href="#sample-02" aria-label="Permalink to &quot;`swao health-check` -- all 11 probes {#sample-02}&quot;">​</a></h3><p><img src="'+g+'" alt="swao health-check with all 11 probes passing"></p><p>Output of <code>swao health-check</code> against a fully-configured Enterprise workspace. All 11 probes report their status:</p><table tabindex="0"><thead><tr><th>Probe</th><th>Result</th></tr></thead><tbody><tr><td>License</td><td>ok -- Enterprise, 56/2000 used</td></tr><tr><td>Playwright / Chromium</td><td>ok -- Chromium build-1223</td></tr><tr><td>SWAO-MCP</td><td>ok -- server configured</td></tr><tr><td>Compliance catalogues</td><td>ok -- GDPR community framework, 53 controls, no integrity issues</td></tr><tr><td>Import templates</td><td>ok -- 3 templates registered</td></tr><tr><td>Traceability</td><td>ok -- 1 app meets targets</td></tr><tr><td>BI export</td><td>ok -- 21 files, all rows and hashes match</td></tr><tr><td>Scope</td><td>INFO -- awaiting Pass 13 run</td></tr><tr><td>Prerequisites</td><td>INFO -- ssh not on PATH (HTTPS clone still works)</td></tr><tr><td>VCS auth</td><td>ok -- 1 of 3 apps authenticated</td></tr><tr><td>Audit ingestion</td><td>INFO -- no audit workspace configured</td></tr></tbody></table><p>Machine fingerprint shown at the bottom -- used when requesting a licence key.</p><hr><h3 id="sample-03" tabindex="-1"><code>swao assess</code> -- multi-pass pipeline streaming <a class="header-anchor" href="#sample-03" aria-label="Permalink to &quot;`swao assess` -- multi-pass pipeline streaming {#sample-03}&quot;">​</a></h3><p><img src="'+m+'" alt="swao assess streaming passes for sovereign-health"></p><p><code>swao assess --app sovereign-health</code> streaming in real time. Passes 01 (inventory), 02 (state analysis), 03 (data classification) and 04 (context ingestion) are visible, each emitting a signal count and wall-clock time on completion. The CTX warnings show the assessment engine probing for optional context files (architecture review, compliance policy, workshop notes) that are not present in this workspace -- the pass continues and the signals that can be derived from source code alone are still emitted.</p><p><strong>The multi-pass pipeline is the heart of SWAO.</strong> Three passes invoke the LLM; everything else is deterministic static analysis.</p><hr><h2 id="power-bi-reports" tabindex="-1">Power BI reports <a class="header-anchor" href="#power-bi-reports" aria-label="Permalink to &quot;Power BI reports&quot;">​</a></h2><h3 id="sample-04" tabindex="-1">Application Dashboard -- overview page <a class="header-anchor" href="#sample-04" aria-label="Permalink to &quot;Application Dashboard -- overview page {#sample-04}&quot;">​</a></h3><p><img src="'+t+'" alt="Power BI Application Report dashboard page"></p><p>The single-app Power BI report opened against a real assessment bundle. The header row shows engagement metadata, the SWAO branding block, and the assessment timestamp. Below: a <strong>Total Signals by outcome</strong> donut chart, a <strong>Controls With Gap by Regime ID</strong> bar chart showing which compliance regimes have the most open gaps, and summary cards for Rationale Coverage and FP Consideration Rate. The lower table exposes the per-signal rationale text that drives every verdict -- this is what makes findings auditor-defensible.</p><p><strong>First page a consultant opens with a customer.</strong> Signals, gaps, and rationale in one view.</p><hr><h3 id="sample-05" tabindex="-1">Compliance matrix -- control-by-control status <a class="header-anchor" href="#sample-05" aria-label="Permalink to &quot;Compliance matrix -- control-by-control status {#sample-05}&quot;">​</a></h3><p><img src="'+a+'" alt="Power BI Compliance page with GDPR control matrix"></p><p>The Compliance page with the full GDPR control matrix. Top cards show: <strong>5 controls Satisfied</strong>, <strong>15 controls With Gap</strong>, <strong>1 Informational</strong>. The main table lists every GDPR control by ID with its severity and verdict (SATISFIED / PARTIAL / UNKNOWN). The Supporting Evidence panel on the right links each verdict to the source signals and evidence URLs that produced it.</p><p><strong>Auditor-grade traceability.</strong> Every cell drills down to the evidence that justified it.</p><hr><h3 id="sample-06" tabindex="-1">Risks page -- risk register with scoring <a class="header-anchor" href="#sample-06" aria-label="Permalink to &quot;Risks page -- risk register with scoring {#sample-06}&quot;">​</a></h3><p><img src="'+u+'" alt="Power BI Risks page with risk register and charts"></p><p>The Risks page with three panels. The <strong>risk register table</strong> at the top shows each risk entry with likelihood, impact, a full trigger description, and a mitigation action -- the top entry (RR-001, score 6) identifies PII fields stored without encryption at the database layer. The <strong>Risk Score by risk_id</strong> horizontal bar chart ranks all risks by score, colour-coded red/orange/green. The <strong>Count of risk_id by category</strong> donut breaks the register by domain: application (60%), business_processes (20%), infrastructure_platform (13%), enablement (7%).</p><p><strong>Risk register that auditors recognise.</strong> Score, trigger, mitigation, and owner in one view.</p><hr><h3 id="sample-07" tabindex="-1">Auditor page -- signal-level rationale <a class="header-anchor" href="#sample-07" aria-label="Permalink to &quot;Auditor page -- signal-level rationale {#sample-07}&quot;">​</a></h3><p><img src="'+b+'" alt="Power BI Auditor page with block-level and signal-level assessments"></p><p>The Auditor page with four summary cards: <strong>Rationale Coverage 1.00</strong>, <strong>FP Consideration Rate 0.21</strong>, <strong>10 Negative Signals</strong>, <strong>1 Control With Gap</strong>. The <strong>Block-Level Assessments</strong> bar chart groups signals by code block and score. Below, the <strong>Signal-Level False-Positive table</strong> shows each signal with its <code>false_positive_considered</code> flag and the LLM-generated <code>overall_rationale</code> text. This is the page an external auditor opens to verify that every finding has a documented derivation.</p><p><strong>Every verdict carries a traceable rationale</strong> -- <code>rule_engine</code> or <code>llm</code>, with reasoning shown.</p><hr><h3 id="sample-08" tabindex="-1">Portfolio Overview -- multi-app dashboard <a class="header-anchor" href="#sample-08" aria-label="Permalink to &quot;Portfolio Overview -- multi-app dashboard {#sample-08}&quot;">​</a></h3><p><img src="'+w+'" alt="Power BI Portfolio Report overview page with four apps"></p><p>The portfolio Power BI report with four assessed applications. Top cards: <strong>4 Total Apps</strong>, <strong>4 Apps With Critical Risk</strong>, <strong>Average Coverage 24.75%</strong>. The <strong>Total Apps by 7R</strong> donut shows the migration strategy distribution across the portfolio. The portfolio table below ranks applications by portability, coverage, negative signals, and weighted risk -- making it straightforward to prioritise which app needs attention first.</p><p><strong>When the portfolio scales to 20 or 50 apps, this page becomes the primary dashboard.</strong></p><hr><h3 id="sample-09" tabindex="-1">Portfolio Auditor Roll-up -- cross-app compliance view <a class="header-anchor" href="#sample-09" aria-label="Permalink to &quot;Portfolio Auditor Roll-up -- cross-app compliance view {#sample-09}&quot;">​</a></h3><p><img src="'+o+'" alt="Power BI Portfolio Auditor Roll-up page"></p><p>The Portfolio Auditor Roll-up page aggregates compliance status across all apps in the portfolio. Top cards show portfolio-level metrics: <strong>Average Coverage 1.00</strong>, <strong>FP Consideration Rate 0.50</strong>, <strong>31 Negative Signals</strong>, <strong>61 Total Signals</strong>. The <strong>Auditor Roll-Up</strong> table lists each app with its individual coverage and FP rate. The <strong>Compliance Status</strong> matrix shows every GDPR control (d-10 view) with its per-app verdict side by side. The <strong>Supporting Evidence</strong> table at the bottom links every verdict to source signals and evidence paths.</p><p><strong>Portfolio governance in one page.</strong> Compliance officers can spot cross-app pattern gaps instantly.</p><hr><h2 id="terminal-interface-tui" tabindex="-1">Terminal interface (TUI) <a class="header-anchor" href="#terminal-interface-tui" aria-label="Permalink to &quot;Terminal interface (TUI)&quot;">​</a></h2><h3 id="sample-10" tabindex="-1">Main Menu <a class="header-anchor" href="#sample-10" aria-label="Permalink to &quot;Main Menu {#sample-10}&quot;">​</a></h3><p><img src="'+f+'" alt="SWAO TUI main menu v0.4.8"></p><p>The SWAO terminal interface launched with no arguments -- <code>swao</code> from any directory. The Enterprise licence status bar shows <code>57/2000 used, expires 2027-06-30</code>. All nine numbered options are visible alongside their descriptions:</p><table tabindex="0"><thead><tr><th>Key</th><th>Option</th><th>What it does</th></tr></thead><tbody><tr><td>1</td><td>Workspace Setup</td><td>init + LLM + credentials wizard</td></tr><tr><td>2</td><td>Health Check</td><td>swao doctor</td></tr><tr><td>3</td><td>Run Assessment</td><td>Application / Audit / Landing Zone + more</td></tr><tr><td>4</td><td>Generate Report</td><td>swao report (text / PDF)</td></tr><tr><td>5</td><td>Publish HTML</td><td>swao publish -- self-contained HTML file</td></tr><tr><td>6</td><td>Export BI</td><td>star schema / PowerBI / Tableau</td></tr><tr><td>7</td><td>Portfolio Operations</td><td>multi-app aggregate (Enterprise)</td></tr><tr><td>8</td><td>Generate TF Modules</td><td>swao generate-tf</td></tr><tr><td>9</td><td>Tools</td><td>lenses / licence / credentials / help</td></tr><tr><td>s</td><td>Open Shell Here</td><td>open command prompt in workspace</td></tr><tr><td>0</td><td>Exit</td><td></td></tr></tbody></table><p>The guidance box at the bottom updates with a description of the highlighted item. Press <code>Ctrl+G</code> to collapse it.</p><hr><h3 id="sample-11" tabindex="-1">Workspace Setup wizard <a class="header-anchor" href="#sample-11" aria-label="Permalink to &quot;Workspace Setup wizard {#sample-11}&quot;">​</a></h3><p><img src="'+s+'" alt="SWAO TUI Workspace Setup wizard step 1 of 7"></p><p>The Workspace Setup wizard (menu item 1) at <strong>Step 1 of 7</strong>. The progress dots at the top show the full journey: Init, LLM, Credentials, Health Check, MCP Client, Playwright, Ready. Step 1 asks for the workspace directory -- pressing Enter accepts the current directory; existing workspaces are detected and reused automatically. The guidance box (Ctrl+G to collapse) explains each field. Escape returns to the main menu at any point.</p><p><strong>The wizard is the recommended first-time experience.</strong> It configures the workspace, LLM provider, credentials, and MCP connector in a single guided flow.</p><hr><h3 id="sample-12" tabindex="-1">Health Check -- TUI view <a class="header-anchor" href="#sample-12" aria-label="Permalink to &quot;Health Check -- TUI view {#sample-12}&quot;">​</a></h3><p><img src="'+r+'" alt="SWAO TUI Health Check screen with 11 probes"></p><p>The Health Check screen (menu item 2) with all 11 probes listed. Seven probes show <strong>OK</strong> in green; Scope and Audit ingestion show <strong>INFO</strong> in cyan; Prerequisites shows <strong>INFO</strong>. The guidance box at the bottom describes the selected probe in detail -- press <code>Ctrl+G</code> to collapse it. &quot;All probes passed.&quot; confirms the workspace is ready for assessment. Press Enter or Escape to return to the main menu.</p><hr><h3 id="sample-13" tabindex="-1">Run Assessment -- type selection <a class="header-anchor" href="#sample-13" aria-label="Permalink to &quot;Run Assessment -- type selection {#sample-13}&quot;">​</a></h3><p><img src="'+i+'" alt="SWAO TUI assessment type selection screen"></p><p>The <strong>Run Assessment</strong> screen (menu item 3) showing the five assessment surfaces. Two are active and immediately usable; three are coming soon:</p><table tabindex="0"><thead><tr><th>Key</th><th>Type</th><th>Status</th></tr></thead><tbody><tr><td>[1]</td><td>Application Assessment</td><td>Active -- <code>swao assess</code>, static + LLM pass suite</td></tr><tr><td>[2]</td><td>Audit Assessment</td><td>Coming soon -- checklist + evidence + verdict</td></tr><tr><td>[3]</td><td>Landing Zone Assessment</td><td>Active -- <code>swao assess --type landing-zone</code>, CSP fit/gap report</td></tr><tr><td>[4]</td><td>LLM Assessment</td><td>Coming soon -- multi-LLM sovereignty benchmarking</td></tr><tr><td>[5]</td><td>Hybrid Assessment</td><td>Coming soon -- source + human evidence combined</td></tr></tbody></table><p>The guidance box describes the highlighted type in full. Application Assessment is the primary entry point: it runs up to 14 analysis passes across inventory, SBOM, cryptography, compliance, 7R synthesis, landing-zone readiness, and produces signals, reports, a BI bundle, and an HTML publication.</p><hr><h3 id="sample-14" tabindex="-1">Publish HTML screen <a class="header-anchor" href="#sample-14" aria-label="Permalink to &quot;Publish HTML screen {#sample-14}&quot;">​</a></h3><p><img src="'+n+'" alt="SWAO TUI Publish HTML screen"></p><p>The Publish screen (menu item 5) with two active publication options and three coming-soon entries:</p><ul><li><strong>[1] Single HTML page</strong> (<code>swao publish --app</code>) -- generates a single self-contained HTML file from the latest assessment run, output to <code>apps/&lt;id&gt;/wsp/publications/&lt;ts&gt;-&lt;id&gt;.html</code> (under 2 MB, email-ready).</li><li><strong>[2] HTML Editor</strong> (<code>swao publish --edit</code>) -- opens the interactive in-browser editor to customise the publication before saving.</li></ul><p>The guidance box describes the output path and format for the selected option.</p><hr><h2 id="mcp-connector" tabindex="-1">MCP connector <a class="header-anchor" href="#mcp-connector" aria-label="Permalink to &quot;MCP connector&quot;">​</a></h2><h3 id="sample-15" tabindex="-1">SWAO connected in Claude Desktop <a class="header-anchor" href="#sample-15" aria-label="Permalink to &quot;SWAO connected in Claude Desktop {#sample-15}&quot;">​</a></h3><p><img src="'+k+'" alt="SWAO MCP connector active in Claude Desktop connectors menu"></p><p>Claude Desktop with the Connectors panel open, showing the <strong>SWAO connector enabled</strong> (blue toggle). The menu shows &quot;Add from SWAO&quot; and &quot;Tool access&quot; entries alongside the standard connector management options. The SWAO connector is part of the ACN General Availability deployment -- no manual configuration required for operators on that tenant.</p><p>Once connected, Claude can call SWAO MCP tools directly from any conversation: read workspace signals, query compliance gaps, and return structured assessment findings grounded in the actual workspace data.</p><hr><h3 id="sample-16" tabindex="-1">MCP: natural-language compliance challenge <a class="header-anchor" href="#sample-16" aria-label="Permalink to &quot;MCP: natural-language compliance challenge {#sample-16}&quot;">​</a></h3><p><img src="'+v+'" alt="Claude answering a GDPR risk question using live SWAO signals"></p><p>A Claude Desktop conversation in the <strong>Starting SWAO</strong> project. The operator asks: <em>&quot;what are the key GDPR risks and how to overcome them?&quot;</em> Claude invokes the <strong>Swao signals</strong> MCP tool and returns a structured, signal-grounded answer:</p><ul><li><strong>High -- DATA-01:</strong> PII stored without database-level encryption. Patient fields (email, phone, notes, transcripts) rely on app-layer encryption only; a DB dump or backup exposes them in plaintext. Fix: enable TDE or column-level encryption on the sovereign target.</li><li><strong>High -- DATA-07:</strong> External identifiers (<code>stripe_customer_id</code>, <code>affiliate_code</code>) lack a deletion policy and are not covered by the existing <code>purge_user()</code> routine. Fix: extend <code>purge_user()</code> or document the legal retention basis in the ROPA.</li><li><strong>High -- DATA-10:</strong> Art. 17 purge routine incomplete -- the <code>cron_hard_purge()</code> function is truncated in the scanned source.</li></ul><p>Every finding is sourced directly from the workspace signal store -- no hallucination, no generic advice. The response uses the same signal IDs and rationale text that appear in the Power BI Auditor page and the HTML publication.</p><p><strong>This is the &quot;wow&quot; moment.</strong> A natural-language question; a structured, auditor-grade answer grounded in the actual codebase.</p>',91)])])}const B=l(y,[["render",P]]);export{W as __pageData,B as default};
